"use client";

import { useEffect, useRef, useState } from "react";
import { X, Send, ArrowLeft } from "lucide-react";
import { Playfair_Display } from "next/font/google";

const playfair = Playfair_Display({
  subsets: ["cyrillic", "latin"],
  weight: ["400", "600", "700", "900"],
});

interface BubbleMessage {
  role: "user" | "assistant";
  content: string;
}

interface MapLocation {
  locationTitle: string;
  lat: number;
  lng: number;
}

interface Props {
  locations: MapLocation[];
}

const REGIONS: Record<string, { center: [number, number]; city: string }> = {
  Минская:     { center: [53.9045, 27.5618], city: "Минск" },
  Брестская:   { center: [52.0976, 23.7341], city: "Брест" },
  Гродненская: { center: [53.6694, 23.8131], city: "Гродно" },
  Витебская:   { center: [55.1848, 30.2016], city: "Витебск" },
  Гомельская:  { center: [52.4412, 30.9878], city: "Гомель" },
  Могилевская: { center: [53.9168, 30.3449], city: "Могилёв" },
};

// Встроенный GeoJSON — без fetch, без ошибок
const BELARUS_GEOJSON = {
  type: "Feature" as const,
  properties: {},
  geometry: {
    type: "Polygon" as const,
    coordinates: [[
      [23.68, 53.94], [23.93, 54.13], [24.36, 54.27], [25.00, 54.57],
      [25.63, 54.78], [26.18, 55.00], [26.64, 55.28], [27.10, 55.79],
      [27.56, 55.93], [28.15, 56.14], [28.70, 56.13], [29.37, 55.93],
      [30.00, 55.64], [30.97, 55.56], [31.77, 54.96], [31.76, 54.07],
      [31.37, 53.97], [31.12, 53.10], [30.56, 52.55], [30.20, 52.04],
      [29.25, 51.37], [28.65, 51.54], [27.74, 51.48], [27.14, 51.75],
      [26.38, 51.87], [25.32, 51.91], [24.37, 51.88], [23.60, 52.09],
      [23.20, 52.49], [23.48, 52.69], [23.63, 53.01], [23.68, 53.94]
    ]]
  }
};

export default function MapWithAI3D({ locations }: Props) {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const initedRef = useRef(false);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const markersRef = useRef<any[]>([]);

  const [activeRegion, setActiveRegion] = useState<string | null>(null);
  const [messages, setMessages] = useState<BubbleMessage[]>([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [is3D, setIs3D] = useState(false);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  // Resize карты при открытии/закрытии панели
  useEffect(() => {
    const t = setTimeout(() => {
      mapRef.current?.resize?.();
    }, 450);
    return () => clearTimeout(t);
  }, [activeRegion]);

  useEffect(() => {
    if (!mapContainerRef.current || initedRef.current) return;
    initedRef.current = true;

    import("maplibre-gl").then((maplibre) => {
      if (!mapContainerRef.current) return;

      if (!document.getElementById("maplibre-css")) {
        const link = document.createElement("link");
        link.id = "maplibre-css";
        link.rel = "stylesheet";
        link.href = "https://cdn.jsdelivr.net/npm/maplibre-gl@3.6.2/dist/maplibre-gl.css";
        document.head.appendChild(link);
      }

      const map = new maplibre.Map({
        container: mapContainerRef.current,
        style: "https://basemaps.cartocdn.com/gl/positron-gl-style/style.json",
        center: [28.0, 53.7],
        zoom: 5.8,
        pitch: 0,
        bearing: 0,
      } as any);

      mapRef.current = map;

      map.on("load", () => {
        if (!mapRef.current) return;

        // Граница Беларуси — из встроенного GeoJSON
        try {
          map.addSource("belarus-border", {
            type: "geojson",
            data: BELARUS_GEOJSON as any,
          });

          // Свечение
          map.addLayer({
            id: "belarus-border-glow",
            type: "line",
            source: "belarus-border",
            paint: {
              "line-color": "rgba(59,130,246,0.15)",
              "line-width": 12,
              "line-blur": 8,
            },
          });

          // Средняя линия
          map.addLayer({
            id: "belarus-border-mid",
            type: "line",
            source: "belarus-border",
            paint: {
              "line-color": "rgba(59,130,246,0.4)",
              "line-width": 3,
              "line-blur": 2,
            },
          });

          // Чёткая линия
          map.addLayer({
            id: "belarus-border-sharp",
            type: "line",
            source: "belarus-border",
            paint: {
              "line-color": "rgba(59,130,246,0.9)",
              "line-width": 1.5,
            },
          });
        } catch (e) {
          console.error("Border error:", e);
        }

        // Маркеры посещённых мест
        locations.forEach((loc) => {
          if (!loc.lat || !loc.lng) return;
          const el = document.createElement("div");
          el.style.cssText = `
            width:8px;height:8px;border-radius:50%;
            background:white;border:1.5px solid #3b82f6;
            box-shadow:0 0 10px rgba(59,130,246,0.5);
          `;
          const marker = new maplibre.Marker({ element: el })
            .setLngLat([loc.lng, loc.lat])
            .addTo(map);
          markersRef.current.push(marker);
        });

        // Пины регионов
        Object.entries(REGIONS).forEach(([region, { center }]) => {
          const el = document.createElement("div");
          el.style.cssText = "display:flex;flex-direction:column;align-items:center;cursor:pointer;transition:transform 0.2s;";
          el.innerHTML = `
            <div style="
              width:14px;height:14px;border-radius:50%;
              background:white;border:2px solid #3b82f6;
              display:flex;align-items:center;justify-content:center;
              box-shadow:0 2px 8px rgba(59,130,246,0.3);
              transition:transform 0.2s;
            ">
              <div style="width:4px;height:4px;background:#3b82f6;border-radius:50%;"></div>
            </div>
            <div style="
              margin-top:4px;
              color:#1a1a1a;
              font-size:10px;
              font-family:serif;
              letter-spacing:0.06em;
              text-shadow:0 1px 3px rgba(255,255,255,0.9),0 0 6px rgba(255,255,255,0.8);
              white-space:nowrap;
              pointer-events:none;
              font-weight:600;
            ">${region}</div>
          `;

          el.addEventListener("mouseenter", () => {
            el.style.transform = "translateY(-4px)";
          });
          el.addEventListener("mouseleave", () => {
            el.style.transform = "translateY(0)";
          });

          el.addEventListener("click", () => {
            map.flyTo({
              center: [center[1], center[0]],
              zoom: 10,
              pitch: 45,
              duration: 1500,
            } as any);
            setIs3D(true);
            openPanel(region);
          });

          const marker = new maplibre.Marker({ element: el })
            .setLngLat([center[1], center[0]])
            .addTo(map);
          markersRef.current.push(marker);
        });
      });
    });

    return () => {
      markersRef.current.forEach(m => m.remove());
      markersRef.current = [];
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
        initedRef.current = false;
      }
    };
  }, []);

  const resetView = () => {
    if (!mapRef.current) return;
    mapRef.current.flyTo({
      center: [28.0, 53.7],
      zoom: 5.8,
      pitch: 0,
      bearing: 0,
      duration: 1500,
    } as any);
    setIs3D(false);
    setActiveRegion(null);
    setMessages([]);
  };

  const openPanel = (region: string) => {
    setActiveRegion(region);
    setMessages([]);
    setInput("");
    fetchAI(region);
  };

  const fetchAI = async (region: string) => {
    setLoading(true);
    setMessages([]);
    try {
      const res = await fetch("/api/ai-assistant", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          message: `Расскажи про ${region} область Беларуси. Ответь строго по шаблону:

🏆 Главная фишка: [одно предложение — что делает эту область уникальной]

📍 Топ-3 места:
- [название] — [5-7 слов почему стоит посетить]
- [название] — [5-7 слов почему стоит посетить]
- [название] — [5-7 слов почему стоит посетить]

❓ [Один вопрос про интересы туриста]`,
        }),
      });
      const data = await res.json();
      const content = data.response?.message ?? (typeof data.response === "string" ? data.response : "Не удалось загрузить 😔");
      setMessages([{ role: "assistant", content }]);
    } catch {
      setMessages([{ role: "assistant", content: "Не удалось загрузить 😔" }]);
    } finally {
      setLoading(false);
    }
  };

  const sendMessage = async () => {
    if (!input.trim() || loading || !activeRegion) return;
    const text = input;
    setMessages(prev => [...prev, { role: "user", content: text }]);
    setInput("");
    setLoading(true);
    try {
      const res = await fetch("/api/ai-assistant", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: `[${activeRegion} область Беларуси] ${text}` }),
      });
      const data = await res.json();
      const content = data.response?.message ?? (typeof data.response === "string" ? data.response : "Ошибка 😔");
      setMessages(prev => [...prev, { role: "assistant", content }]);
    } catch {
      setMessages(prev => [...prev, { role: "assistant", content: "Ошибка соединения 😔" }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex w-full h-full overflow-hidden rounded-xl border border-gray-200 shadow-inner bg-white">
      <style>{`
        .maplibregl-ctrl-attrib { font-size: 9px !important; }
      `}</style>

      {/* Карта */}
      <div className="relative flex-1 h-full min-w-0">
        <div ref={mapContainerRef} className="w-full h-full" />

        {/* Кнопка назад */}
        <button
          onClick={resetView}
          className="absolute top-4 left-4 z-10 w-10 h-10 flex items-center justify-center bg-white/90 backdrop-blur-md border border-gray-200 rounded-full hover:bg-gray-900 hover:text-white transition shadow-lg"
          title="Сбросить вид"
        >
          <ArrowLeft className="w-4 h-4" />
        </button>
      </div>

      {/* Боковая панель */}
      {activeRegion && (
        <div className="w-full md:w-[40%] h-full bg-white border-l border-gray-200 flex flex-col shadow-2xl"
          style={{ animation: "slideIn 0.4s cubic-bezier(0.4,0,0.2,1) both" }}>
          <style>{`
            @keyframes slideIn {
              from { opacity:0; transform:translateX(20px); }
              to   { opacity:1; transform:translateX(0); }
            }
          `}</style>

          {/* Хедер */}
          <div className="p-8 border-b border-gray-100 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] uppercase tracking-[0.3em] text-gray-400 mb-1">
                {REGIONS[activeRegion]?.city || "Регион"}
              </span>
              <h2 className={`${playfair.className} text-2xl font-black text-gray-900 leading-none`}>
                {activeRegion} область
              </h2>
            </div>
            <button
              onClick={() => { setActiveRegion(null); setMessages([]); }}
              className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-black"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          {/* Сообщения */}
          <div className="flex-1 overflow-y-auto p-8 space-y-6">
            {loading && messages.length === 0 && (
              <div className="space-y-3">
                {[0.75, 1, 0.83, 0.67, 1, 0.8].map((w, i) => (
                  <div key={i} className="h-4 bg-gray-100 rounded animate-pulse" style={{ width: `${w * 100}%` }} />
                ))}
              </div>
            )}

            {messages.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
                {msg.role === "assistant" ? (
                  <div className="w-full border-b border-gray-100 pb-6">
                    <p className={`${playfair.className} text-xl font-bold text-gray-900 mb-3`}>
                      {activeRegion}
                    </p>
                    <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">
                      {msg.content}
                    </p>
                  </div>
                ) : (
                  <div className="bg-gray-900 text-white text-sm px-4 py-3 rounded-sm max-w-[85%]">
                    {msg.content}
                  </div>
                )}
              </div>
            ))}

            {loading && messages.length > 0 && (
              <div className="flex gap-1.5 items-center text-gray-400 text-sm italic">
                <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: "0ms" }} />
                <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: "150ms" }} />
                <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: "300ms" }} />
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Инпут */}
          <div className="p-6 bg-white border-t border-gray-100">
            <div className="flex gap-3 items-center border-b border-black pb-2 focus-within:border-gray-400 transition-colors">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && sendMessage()}
                placeholder="ВАШ ВОПРОС..."
                disabled={loading}
                className="flex-1 bg-transparent py-2 text-xs focus:outline-none text-gray-900 placeholder:text-gray-300 uppercase tracking-widest font-bold disabled:opacity-50"
              />
              <button
                onClick={sendMessage}
                disabled={loading || !input.trim()}
                className="text-black hover:text-gray-500 transition disabled:opacity-30"
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}